#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>
#include <cuda_runtime.h>

#ifndef DEVICE_TYPE_DEFAULT
#define DEVICE_TYPE_DEFAULT 0
#endif

#define TOL      (0.001)
#define STR_SIZE (256)
#define MAX_PD   (3.0e6)

#define PRECISION    0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI         100

#define FACTOR_CHIP	0.5

#define WG_SIZE_X (64)
#define WG_SIZE_Y (4)

float t_chip      = 0.0005;
float chip_height = 0.016;
float chip_width  = 0.016;
float amb_temp    = 80.0;

void usage(int argc, char **argv)
{
  fprintf(stderr, "Usage: %s <-n rows/cols> <-l layers> <-i iterations> <-f powerFile tempFile outputFile> [-d device]\n", argv[0]);
  fprintf(stderr, "\t<rows/cols>  - number of rows/cols in the grid (positive integer)\n");
  fprintf(stderr, "\t<layers>  - number of layers in the grid (positive integer)\n");
  fprintf(stderr, "\t<iteration> - number of iterations\n");
  fprintf(stderr, "\t<powerFile>  - name of the file containing the initial power values of each cell\n");
  fprintf(stderr, "\t<tempFile>  - name of the file containing the initial temperature values of each cell\n");
  fprintf(stderr, "\t<outputFile - output file\n");
  exit(1);
}

char *err_code(cudaError_t err_in)
{
    switch (err_in) {
        case cudaSuccess: return (char*)" cudaSuccess ";
        case cudaErrorInvalidValue: return (char*)" cudaErrorInvalidValue ";
        case cudaErrorMemoryAllocation: return (char*)" cudaErrorMemoryAllocation ";
        case cudaErrorInitializationError: return (char*)" cudaErrorInitializationError ";
        case cudaErrorLaunchFailure: return (char*)" cudaErrorLaunchFailure ";
        case cudaErrorInvalidDevice: return (char*)" cudaErrorInvalidDevice ";
        default: return (char*)"UNKNOWN ERROR";
    }
}

void fatal(char *s)
{
  fprintf(stderr, "Error: %s\n", s);
}

char *load_kernel_source(const char *filename) {
    FILE *file = fopen(filename, "r");
    if (file == NULL) fatal("Error opening kernel source file\n");
    if (fseek(file, 0, SEEK_END)) fatal("Error reading kernel source file\n");
    size_t size = ftell(file);
    char *source = (char *) malloc(size + 1);
    fseek(file, 0, SEEK_SET);
    if (fread(source, 1, size, file) != size) fatal("Error reading kernel source file\n");
    source[size] = '\0';
    return source;
}

void readinput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {
    int i,j,k;
    FILE *fp;
    char str[STR_SIZE];
    float val;
    if( (fp  = fopen(file, "r" )) ==0 ) fatal( "The file was not opened" );
    for (i=0; i <= grid_rows-1; i++) 
      for (j=0; j <= grid_cols-1; j++)
        for (k=0; k <= layers-1; k++)
          {
            if (fgets(str, STR_SIZE, fp) == NULL) fatal("Error reading file\n");
            if (feof(fp)) fatal("not enough lines in file");
            if ((sscanf(str, "%f", &val) != 1)) fatal("invalid file format");
            vect[i*grid_cols+j+k*grid_rows*grid_cols] = val;
          }
    fclose(fp);	
}

void writeoutput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {
    int i,j,k, index=0;
    FILE *fp;
    char str[STR_SIZE];
    if( (fp = fopen(file, "w" )) == 0 ) printf( "The file was not opened\n" );
    for (i=0; i < grid_rows; i++) 
      for (j=0; j < grid_cols; j++)
        for (k=0; k < layers; k++)
          {
            sprintf(str, "%d\t%g\n", index, vect[i*grid_cols+j+k*grid_rows*grid_cols]);
            fputs(str,fp);
            index++;
          }
    fclose(fp);	
}

void computeTempCPU(float *pIn, float* tIn, float *tOut, 
        int nx, int ny, int nz, float Cap, 
        float Rx, float Ry, float Rz, 
        float dt, float amb_temp, int numiter) 
{   float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw =stepDivCap/ Rx;
    cn = cs =stepDivCap/ Ry;
    ct = cb =stepDivCap/ Rz;
    cc = 1.0 - (2.0*ce + 2.0*cn + 3.0*ct);
    int c,w,e,n,s,b,t;
    int x,y,z;
    int i = 0;
    do{
        for(z = 0; z < nz; z++)
            for(y = 0; y < ny; y++)
                for(x = 0; x < nx; x++)
                {
                    c = x + y * nx + z * nx * ny;
                    w = (x == 0) ? c : c - 1;
                    e = (x == nx - 1) ? c : c + 1;
                    n = (y == 0) ? c : c - nx;
                    s = (y == ny - 1) ? c : c + nx;
                    b = (z == 0) ? c : c - nx * ny;
                    t = (z == nz - 1) ? c : c + nx * ny;
                    tOut[c] = tIn[c]*cc + tIn[n]*cn + tIn[s]*cs + tIn[e]*ce + tIn[w]*cw + tIn[t]*ct + tIn[b]*cb + (dt/Cap) * pIn[c] + ct*amb_temp;
                }
        float *temp = tIn;
        tIn = tOut;
        tOut = temp; 
        i++;
    }
    while(i < numiter);
}

float accuracy(float *arr1, float *arr2, int len)
{
    float err = 0.0; 
    int i;
    for(i = 0; i < len; i++)
    {
        err += (arr1[i]-arr2[i]) * (arr1[i]-arr2[i]);
    }
    return (float)sqrt(err/len);
}

#ifdef TIMING
void tvsub(struct timeval *t1, struct timeval *t0, struct timeval *out)
{
    out->tv_sec = t1->tv_sec - t0->tv_sec;
    out->tv_usec = t1->tv_usec - t0->tv_usec;
    if (out->tv_usec < 0) {
        out->tv_sec--;
        out->tv_usec += 1000000;
    }
}
#endif

int main(int argc, char** argv)
{
    char *pfile = NULL, *tfile = NULL, *ofile = NULL;
    int iterations = 0;
    int numCols    = 0;
    int numRows    = 0;
    int layers     = 0;
    int device_id_inuse = 0;              
    int cur_arg;

    for (cur_arg = 1; cur_arg<argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-h") == 0) {
			usage(argc, argv);
        }
        else if (strcmp(argv[cur_arg], "-n") == 0) {
            if (argc >= cur_arg + 1) {
                numCols = numRows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-l") == 0) {
            if (argc >= cur_arg + 1) {
                layers = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-i") == 0) {
            if (argc >= cur_arg + 1) {
                iterations = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-f") == 0) {
            if (argc >= cur_arg + 3) {
                pfile = argv[cur_arg+1];
                tfile = argv[cur_arg+2];
                ofile = argv[cur_arg+3];
                cur_arg += 3;
            }
        }
        else if (strcmp(argv[cur_arg], "-d") == 0) {
            if (argc >= cur_arg + 1) {
                device_id_inuse = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
    }

	if (numCols == 0 || layers == 0 || iterations == 0 || pfile == NULL) {
		usage(argc, argv);
	}

  float dx         = chip_height/numRows;
  float dy         = chip_width/numCols;
  float dz         = t_chip/layers;

  float Cap        = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * dx * dy;
  float Rx         = dy / (2.0 * K_SI * t_chip * dx);
  float Ry         = dx / (2.0 * K_SI * t_chip * dy);
  float Rz         = dz / (K_SI * dx * dy);

  float max_slope  = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
  float dt         = PRECISION / max_slope;

  float ce, cw, cn, cs, ct, cb, cc;
  float stepDivCap = dt / Cap;
  ce               = cw                                              = stepDivCap/ Rx;
  cn               = cs                                              = stepDivCap/ Ry;
  ct               = cb                                              = stepDivCap/ Rz;
  cc               = 1.0 - (2.0*ce + 2.0*cn + 3.0*ct);

  int size = numCols * numRows * layers;
  float*        tIn      = (float*) calloc(size,sizeof(float));
  float*        pIn      = (float*) calloc(size,sizeof(float));
  float*        tempCopy = (float*)malloc(size * sizeof(float));
  float*        tempOut  = (float*) calloc(size,sizeof(float));

  readinput(tIn,numRows, numCols, layers, tfile);
  readinput(pIn,numRows, numCols, layers, pfile);

  memcpy(tempCopy,tIn, size * sizeof(float));

#ifdef TIMING
  struct timeval tv;
  struct timeval tv_total_start, tv_total_end;
  struct timeval tv_init_end;
  struct timeval tv_h2d_start, tv_h2d_end;
  struct timeval tv_d2h_start, tv_d2h_end;
  struct timeval tv_kernel_start, tv_kernel_end;
  struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
  struct timeval tv_close_start, tv_close_end;
  float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
              d2h_time = 0, close_time = 0, total_time = 0;
  gettimeofday(&tv_total_start, NULL);
#endif

  cudaDeviceProp prop;
  int num_devices = 0;
  cudaError_t err = cudaGetDeviceCount(&num_devices);
  if (err != cudaSuccess || num_devices <= 0) {
      printf("Error: Failed to find a CUDA device!\n%s\n", err_code(err));
      return EXIT_FAILURE;
  }

  printf("num_devices = %d\n", num_devices);
  if (device_id_inuse >= num_devices) {
      printf("Invalid Device Number\n");
      return EXIT_FAILURE;
  }

  err = cudaGetDeviceProperties(&prop, device_id_inuse);
  if (err != cudaSuccess) {
      printf("ERROR: cudaGetDeviceProperties failed\n");
      return EXIT_FAILURE;
  }

  printf(" \n Device is  %s \n", prop.name);

  err = cudaSetDevice(device_id_inuse);
  if (err != cudaSuccess) {
      printf("ERROR: cudaSetDevice failed\n");
      return EXIT_FAILURE;
  }

#ifdef TIMING
  gettimeofday(&tv_init_end, NULL);
  tvsub(&tv_init_end, &tv_total_start, &tv);
  init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

  float *d_a, *d_b, *d_c;
  err = cudaMalloc(&d_a, sizeof(float) * size);
  err |= cudaMalloc(&d_b, sizeof(float) * size);
  err |= cudaMalloc(&d_c, sizeof(float) * size);

  if (err != cudaSuccess) {
      printf("Error: Failed to allocate device memory!\n%s\n", err_code(err));
      exit(1);
  }

#ifdef TIMING
  gettimeofday(&tv_mem_alloc_end, NULL);
  tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
  mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

  err = cudaMemcpy(d_a, tIn, sizeof(float) * size, cudaMemcpyHostToDevice);
  if (err != cudaSuccess) {
      printf("Error: Failed to write tIn to source array!\n%s\n", err_code(err));
      exit(1);
  }

  err = cudaMemcpy(d_b, pIn, sizeof(float) * size, cudaMemcpyHostToDevice);
  if (err != cudaSuccess) {
      printf("Error: Failed to write pIn to source array!\n%s\n", err_code(err));
      exit(1);
  }

  err = cudaMemcpy(d_c, tempOut, sizeof(float) * size, cudaMemcpyHostToDevice);
  if (err != cudaSuccess) {
      printf("Error: Failed to write tempOut to source array!\n%s\n", err_code(err));
      exit(1);
  }

  dim3 block(WG_SIZE_X, WG_SIZE_Y, 1);
  dim3 grid((numCols + WG_SIZE_X - 1) / WG_SIZE_X, (numRows + WG_SIZE_Y - 1) / WG_SIZE_Y, 1);

  int j;
  for(j = 0; j < iterations; j++) {
      hotspotOpt1<<<grid, block>>>(d_b, d_a, d_c, stepDivCap, numCols, numRows, layers, ce, cw, cn, cs, ct, cb, cc);

      err = cudaDeviceSynchronize();
      if (err != cudaSuccess) {
          printf("Error: Failed to execute kernel!\n%s\n", err_code(err));
          return EXIT_FAILURE;
      }

      float *temp = d_a;
      d_a         = d_c;
      d_c         = temp;
  }

  err = cudaMemcpy(tempOut, d_c, sizeof(float) * size, cudaMemcpyDeviceToHost);
  if (err != cudaSuccess) {
      printf("Error: Failed to read output array!\n%s\n", err_code(err));
      exit(1);
  }

#ifdef TIMING
  gettimeofday(&tv_close_start, NULL);
#endif

  cudaFree(d_a);
  cudaFree(d_b);
  cudaFree(d_c);

#ifdef TIMING
  gettimeofday(&tv_close_end, NULL);
  tvsub(&tv_close_end, &tv_close_start, &tv);
  close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
  tvsub(&tv_close_end, &tv_total_start, &tv);
  total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

  printf("Init: %f\n", init_time);
  printf("MemAlloc: %f\n", mem_alloc_time);
  printf("HtoD: %f\n", h2d_time);
  printf("Exec: %f\n", kernel_time);
  printf("DtoH: %f\n", d2h_time);
  printf("Close: %f\n", close_time);
  printf("Total: %f\n", total_time);
#endif

  float* answer = (float*)calloc(size, sizeof(float));
  computeTempCPU(pIn, tempCopy, answer, numCols, numRows, layers, Cap, Rx, Ry, Rz, dt, amb_temp, iterations);
  float acc = accuracy(tempOut,answer,numRows*numCols*layers);
  printf("Accuracy: %e\n",acc);

  writeoutput(tempOut,numRows,numCols,layers,ofile);

  return 0;
}
